
'use server';

import { generateKissVideo } from '@/ai/flows/generate-kiss-video';
import type { GenerateKissVideoInput, GenerateKissVideoOutput } from '@/ai/flows/generate-kiss-video';
import { checkUserSubscriptionAdmin, decrementUserCreditsAdmin } from '@/lib/firebase/firebase-admin';

export interface CreateKissVideoActionInput extends GenerateKissVideoInput {
    userId: string;
}

export async function createKissVideoAction(input: CreateKissVideoActionInput): Promise<GenerateKissVideoOutput> {
  try {
    const userProfile = await checkUserSubscriptionAdmin(input.userId);

    if (!userProfile) {
      return { error: 'User profile not found. Could not verify subscription status.' };
    }
    
    // This check is robust. The user profile is upgraded by the webhook.
    // If the check happens before the webhook has finished, this might fail, but it's a race condition.
    // The primary check is to prevent non-paying users from generating.
    if (!userProfile.isSubscribed && userProfile.credits <= 0) {
      return { error: 'You have no remaining credits. Please subscribe to continue.' };
    }

    const result = await generateKissVideo({
      image1DataUri: input.image1DataUri,
      image2DataUri: input.image2DataUri,
    });
    
    // Only decrement credits if generation was successful and user is not subscribed.
    // We re-check the profile in case the webhook updated it during generation.
    if (!result.error) {
        const finalProfile = await checkUserSubscriptionAdmin(input.userId);
        if (finalProfile && !finalProfile.isSubscribed) {
            await decrementUserCreditsAdmin(input.userId);
        }
    }
    
    return result;

  } catch (e) {
    console.error('[ACTION_ERROR] createKissVideoAction failed:', e);
    const message = e instanceof Error ? e.message : 'An unknown error occurred during video generation.';
    return { error: message };
  }
}

    